import{_ as t,o as e,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const F=JSON.parse('{"title":"F02: 營業現金流與獲利品質 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3680_家登/20260509/F02_營業現金流與獲利品質.md","filePath":"審計報告庫/財務審計/3680_家登/20260509/F02_營業現金流與獲利品質.md"}'),l={name:"審計報告庫/財務審計/3680_家登/20260509/F02_營業現金流與獲利品質.md"};function o(n,a,s,h,d,c){return e(),i("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f02-營業現金流與獲利品質-財務審計專家報告" tabindex="-1">F02: 營業現金流與獲利品質 - 財務審計專家報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-財務審計專家報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>CFO 與稅後淨利之關係？獲利是否具備實質現金支撐？識別「有獲利無現金」的盈餘品質風險。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CFO/NI 比值 259-467% 含金量極高，但 FCF 連 4 年為負（累計 -46.1 億），屬賺現金但留不住現金的資本密集模式。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：2025年度</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>CFO</strong>：8.53 億（2022）→ 12.14 億（2023）→ 9.67 億（2024）→ 13.91 億（2025），營運活動現金流入穩健成長</li><li><strong>Net Income</strong>：2.52 億→ 2.60 億→ 2.95 億→ 5.36 億</li><li><strong>CFO/NI 比值</strong>：338% → 467% → 328% → 259%，4 年均 &gt;250%，遠超製造業 100% 基準線</li><li><strong>FCF</strong>：-3.67 億→ -7.46 億→ -23.45 億→ -11.11 億，4 年累計 -45.69 億</li><li><strong>診斷見解</strong>：現金流量表揭示公司「營運造血能力強」但「投資耗血更劇」。2024 年 FCF 缺口達 23.45 億為最危險年份，主因 CapEx 暴增至 17.03 億。折舊（2025 年 5.83 億）是 CFO 的重要非現金貢獻，若扣除折舊，實質營運現金仍為正，顯示本業可自給。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、cfo-ni-比值深度拆解" tabindex="-1">一、CFO/NI 比值深度拆解 <a class="header-anchor" href="#一、cfo-ni-比值深度拆解" aria-label="Permalink to &quot;一、CFO/NI 比值深度拆解&quot;">​</a></h3><p>CFO 大幅超過淨利，4 年均值 347.8%。2025 年 259% 為 4 年最低仍在優質區間。主因是折舊（2.35→5.83 億）與攤銷（0.23→0.53 億）等非現金費用。折舊隨新廠完工續升，短期 CFO/NI 可維持高水位，但不代表營運資金效率提升，純屬折舊掩蓋效應。</p><h3 id="二、非現金項目核實" tabindex="-1">二、非現金項目核實 <a class="header-anchor" href="#二、非現金項目核實" aria-label="Permalink to &quot;二、非現金項目核實&quot;">​</a></h3><p>應收帳款增加額從 4.31 億收斂至 +0.14 億（2025），收款效率顯著改善。存貨從 2024 年累增 9.95 億到 2025 年反轉減少 0.64 億，若持續將釋放營運資金。</p><h3 id="三、fcf-結構性風險" tabindex="-1">三、FCF 結構性風險 <a class="header-anchor" href="#三、fcf-結構性風險" aria-label="Permalink to &quot;三、FCF 結構性風險&quot;">​</a></h3><p>4 年 FCF 累計 -45.69 億，最大缺口 2024 年 -23.45 億。2024 年 CapEx 17.03 億 + 存貨 1.61 億 + 應收 5.87 億同時發生，增量營收的現金貢獻被營運週轉稀釋。2025 年缺口縮至 11.11 億，管理層已啟動控管。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析（Skepticism Mandate） <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析（Skepticism Mandate）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>CFO 高度依賴折舊掩蓋</strong>：扣除折舊 5.83 億後實質營運現金 8.08 億。擴廠完畢折舊穩定後，若獲利未同步提升，CFO/NI 將顯著回落，形成報表<strong>褪色壓力</strong>。</li><li><strong>CapEx 56.97 億遠超 CFO 44.28 億</strong>，FCF 為負必持續籌資。利息費用從 0.55 億增至 1.75 億（+218%），財務槓桿侵蝕彈性。</li><li><strong>2024 年營收 +24.6% 但 CFO 反跌 20.3%</strong>，增量營收吃掉 5.87 億應收款，顯示大客戶議價力強。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>CFO/NI 259% 即使在最差年仍優於同業</strong>，營運造血能力強健。</li><li><strong>營運資金管理改善</strong>：2025 年應收幾無增加、存貨反轉減少，管理層已啟動優化。</li><li><strong>期末現金 51.09 億</strong>充足支撐短期營運。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>獲利品質本質優異——CFO &gt; NI 證明利潤真實。核心問題在資金配置效率，若日本新廠貢獻現金流使 FCF 轉正則為轉折點。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (cashflow_quality 3680 2022 2025)</li><li>原始數據：FinMind TaiwanStockCashFlowsStatement + TaiwanStockFinancialStatements</li><li>交叉核對：數據採集器.py (cash_flow 3680 2022-01-01 2026-05-09)</li><li>查詢參數：stock_id=3680, start=2022-01-01, end=2025-12-31</li><li>數據查詢日期：2026-05-09</li></ul>',24)])])}const u=t(l,[["render",o]]);export{F as __pageData,u as default};
